import random

def is_prime(num):
    """Check if a number is prime."""
    if num < 2:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

def prime_generator():
    """Generator that yields prime numbers indefinitely."""
    num = 2
    while True:
        if is_prime(num):
            yield num
        num += 1

