def prime_generator():
    sieve = [True] * 1000001
    sieve[0] = sieve[1] = False

    for i in range(2, int(1000000 ** 0.5) + 3):
        if sieve[i]:
            for multiple in range(i * i, 1000001, i):
                sieve[multiple] = False

    for i in range(1000001):
        if sieve[i]:
            yield i

